mapper.select:
SELECT id, product_id, sku_name, price, stock, locked_stock, create_time
FROM sku
WHERE id = #{id}

mapper.update:
UPDATE sku
SET stock        = stock - #{quantity},
    locked_stock = locked_stock + #{quantity}
WHERE id = #{skuId}
  AND stock >= #{quantity}

UPDATE sku
SET stock        = stock + #{quantity},
    locked_stock = locked_stock - #{quantity}
WHERE id = #{skuId}
  AND locked_stock >= #{quantity}

UPDATE sku
SET locked_stock = locked_stock - #{quantity}
WHERE id = #{skuId}
  AND locked_stock >= #{quantity}
